def build_tree(node, char):
    if node is None:
        return {'char': char.lower(), 'left': None, 'right': None}
    if char.lower() < node['char']:
        node['left'] = build_tree(node['left'], char)
    elif char.lower() > node['char']:
        node['right'] = build_tree(node['right'], char)
    return node

